import React from 'react';
import { Paper, BottomNavigation as MuiBottomNavigation, BottomNavigationAction } from '@mui/material';
import { styled } from '@mui/material/styles';
import { Home, EmojiEvents, Person } from '@mui/icons-material';
import { useLocation, useNavigate } from 'react-router-dom';

const StyledBottomNavigation = styled(Paper)(({ theme }) => ({
  position: 'fixed',
  bottom: 0,
  left: 0,
  right: 0,
  zIndex: 100,
  borderTopLeftRadius: theme.shape.borderRadius * 3,
  borderTopRightRadius: theme.shape.borderRadius * 3,
  overflow: 'hidden',
  boxShadow: theme.shadows[3],
}));

const BottomNavigationBar: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const currentPath = location.pathname.split('/')[1] || '/';
  
  const handleChange = (event: React.SyntheticEvent<Element, Event>, newValue: string) => {
    navigate(newValue);
  };
  
  return (
    <StyledBottomNavigation>
      <MuiBottomNavigation
        value={currentPath === '/' ? '/' : `/${currentPath}`}
        onChange={handleChange}
        showLabels
      >
        <BottomNavigationAction 
          label="Главная" 
          value="/" 
          icon={<Home />} 
        />
        <BottomNavigationAction 
          label="Розыгрыши" 
          value="/raffles" 
          icon={<EmojiEvents />} 
        />
        <BottomNavigationAction 
          label="Профиль" 
          value="/profile" 
          icon={<Person />} 
        />
      </MuiBottomNavigation>
    </StyledBottomNavigation>
  );
};

export default BottomNavigationBar;
